// HasProperty: check own + prototype chain (ES spec [[HasProperty]])
static bool js_has_property(Item obj, Item key) {
    // Proxy [[HasProperty]] trap
    if (js_is_proxy(obj)) {
        Item result = js_proxy_trap_has(obj, key);
        return js_is_truthy(result);
    }
    // String primitives: character indices 0..length-1 are always present
    if (get_type_id(obj) == LMD_TYPE_STRING) {
        String* s = it2s(obj);
        if (!s) return false;
        Item k = js_to_string(key);
        String* ks = it2s(k);
        if (!ks) return false;
        if (ks->len == 6 && strncmp(ks->chars, "length", 6) == 0) return true;
        // parse numeric index
        bool is_num = (ks->len > 0 && ks->len <= 10);
        int64_t idx = 0;
        if (is_num) {
            for (int i = 0; i < (int)ks->len; i++) {
                char c = ks->chars[i];
                if (c < '0' || c > '9') { is_num = false; break; }
                idx = idx * 10 + (c - '0');
            }
            if (is_num && ks->len > 1 && ks->chars[0] == '0') is_num = false;
        }
        if (is_num && idx >= 0 && idx < (int64_t)s->len) return true;
        return false;
    }
    if (it2b(js_has_own_property(obj, key))) return true;
    // walk prototype chain — for plain MAPs without explicit __proto__, use js_get_prototype
    // (returns ItemNull for bare object literals) rather than js_get_prototype_of (which returns
    // implicit Object.prototype). This matches pre-v37 HasProperty semantics: an array-like
    // object like {2:2, length:20} doesn't reach Object.prototype, so Object.prototype[k] values
    // captured before getters can fire don't corrupt array-method snapshots.
    Item proto;
    if (get_type_id(obj) == LMD_TYPE_MAP && obj.map->map_kind == MAP_KIND_PLAIN) {
        proto = js_get_prototype(obj);  // only explicit __proto__; ItemNull for plain object literals
    } else {
        proto = js_get_prototype_of(obj);  // arrays, functions, typed arrays, Objects with __proto__
    }
    int depth = 0;
    while (proto.item != ItemNull.item && get_type_id(proto) != LMD_TYPE_UNDEFINED && depth < 32) {
        if (it2b(js_has_own_property(proto, key))) return true;
        proto = js_get_prototype_of(proto);
        depth++;
    }
    return false;
}

// Convert an array-like object (MAP with length + numeric indices) to an Array
static Item js_array_like_to_array(Item obj) {
    // Get length property — per ES spec, length getter may throw (step 2 of forEach/map/etc.)
    Item length_key = (Item){.item = s2it(heap_create_name("length", 6))};
    Item len_val = js_property_get(obj, length_key);
    // propagate exception from length getter (e.g. Object.defineProperty getter that throws)
    if (js_check_exception()) return ItemNull;
    int len = (int)js_get_number(len_val);
    if (js_check_exception()) return ItemNull;
    if (len < 0) len = 0;
    if (len > 100000) len = 100000; // safety cap
    Item result = js_array_new(len);
    Array* arr = result.array;
    Item hole = (Item){.item = JS_DELETED_SENTINEL_VAL};
    for (int i = 0; i < len; i++) {
        char buf[16];
        int blen = snprintf(buf, sizeof(buf), "%d", i);
        Item idx_key = (Item){.item = s2it(heap_create_name(buf, blen))};
        // ES spec: check HasProperty (includes prototype chain) to preserve holes
        bool has = js_has_property(obj, idx_key);
        Item val = hole;
        // v37: For plain MAPs without __proto__, js_has_property/js_property_get
        // skip Object.prototype. If property is missing or undefined here, check
        // Object.prototype manually (unless it's an own setter-only accessor).
        bool plain_map = (get_type_id(obj) == LMD_TYPE_MAP && obj.map->map_kind == MAP_KIND_PLAIN);
        bool is_own_setter_only = false;
        if (plain_map && blen < 200) {
            char sk[256];
            int sklen = snprintf(sk, sizeof(sk), "__set_%.*s", blen, buf);
            bool sk_found = false;
            js_map_get_fast(obj.map, sk, sklen, &sk_found);
            if (sk_found) {
                bool gk_found = false;
                char gk[256];
                int gklen = snprintf(gk, sizeof(gk), "__get_%.*s", blen, buf);
                js_map_get_fast(obj.map, gk, gklen, &gk_found);
                if (!gk_found) is_own_setter_only = true;
            }
        }
        if (has) {
            val = js_property_get(obj, idx_key);
            if (get_type_id(val) == LMD_TYPE_UNDEFINED && plain_map && !is_own_setter_only) {
                Map* obj_proto = js_resolve_object_prototype();
                if (obj_proto && obj.map != obj_proto) {
                    Item proto_val = js_property_get((Item){.map = obj_proto}, idx_key);
                    if (get_type_id(proto_val) != LMD_TYPE_UNDEFINED) {
                        val = proto_val;
                    }
                }
            }
        } else if (plain_map && !is_own_setter_only) {
            // js_has_property returned false because plain MAPs skip Object.prototype.
            // Check Object.prototype explicitly: if property is present there, treat as inherited.
            Map* obj_proto = js_resolve_object_prototype();
            if (obj_proto && obj.map != obj_proto) {
                Item op_item = (Item){.map = obj_proto};
                if (it2b(js_has_own_property(op_item, idx_key))) {
                    val = js_property_get(op_item, idx_key);
                }
            }
        }
        if (i < arr->capacity) {
            arr->items[i] = val;
            if (i >= arr->length) arr->length = i + 1;
        } else {
            js_array_push_item_direct(arr, val);
        }
    }
    return result;
}

